uniform sampler2D uPreviousFrame;
uniform float uTime;
uniform vec2 uResolution;

// --- MAIN SETTINGS ---
uniform float uGridSize;       // 10.0 (Grid density)
uniform float uThreshold;      // 0.15 (Edge sensitivity)
uniform float uAppearSpeed;    // 1.0 (Speed of appear/disappear cycle)

// --- STYLE SETTINGS ---
uniform float uLineThickness;  // 0.002
uniform vec3 uLineColor;       // vec3(0.4, 0.8, 0.4)
uniform vec3 uBoxColor;        // vec3(0.6, 1.0, 0.6)
uniform float uTextOpacity;    // 1.0

// --- BOX SHAPE ---
uniform float uMinHeight;      // 0.2
uniform float uMaxHeight;      // 1.2
uniform float uMinWidth;       // 0.2
uniform float uVerticalChance; // 0.7

// Random Hash
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// --- BITMAP FONT ---
float digit(vec2 uv, int n) {
    if (uv.x < 0.0 || uv.x > 1.0 || uv.y < 0.0 || uv.y > 1.0) return 0.0;
    int x = int(floor(uv.x * 3.0));
    int y = int(floor(uv.y * 5.0));
    bool on = false;
    if (n==0) on = (x==1 && y!=0 && y!=4) || (y==0 || y==4);
    else if (n==1) on = (x==2);
    else if (n==2) on = (y==0 || y==2 || y==4) || (x==2 && y==3) || (x==0 && y==1);
    else if (n==3) on = (y==0 || y==2 || y==4) || (x==2);
    else if (n==4) on = (y==2) || (x==2) || (x==0 && y>2);
    else if (n==5) on = (y==0 || y==2 || y==4) || (x==0 && y>2) || (x==2 && y<2);
    else if (n==6) on = (y==0 || y==2 || y==4) || (x==0) || (x==2 && y<2);
    else if (n==7) on = (y==4) || (x==2);
    else if (n==8) on = (y==0 || y==2 || y==4) || (x==0) || (x==2);
    else if (n==9) on = (y==0 || y==2 || y==4) || (x==2) || (x==0 && y>2);
    return on ? 1.0 : 0.0;
}

float drawNumberSequence(vec2 uv, vec2 id) {
    float result = 0.0;
    float rnd = hash(id);
    int n1 = int(mod(rnd * 10.0, 10.0));
    int n2 = int(mod(rnd * 100.0, 10.0));
    int n3 = int(mod(rnd * 1000.0, 10.0));
    result += digit(vec2(uv.x * 3.0, uv.y), n1);
    result += digit(vec2((uv.x - 0.4) * 3.0, uv.y), n2);
    result += digit(vec2((uv.x - 0.8) * 3.0, uv.y), n3);
    return result;
}

// Edge Detection
float getEdgeIntensity(vec2 uv) {
    if(uv.x < 0.0 || uv.x > 1.0 || uv.y < 0.0 || uv.y > 1.0) return 0.0;
    vec2 pixel = 1.0 / uResolution;
    vec3 c = texture2D(uPreviousFrame, uv).rgb;
    vec3 n = texture2D(uPreviousFrame, uv + vec2(0.0, pixel.y*2.0)).rgb;
    vec3 e = texture2D(uPreviousFrame, uv + vec2(pixel.x*2.0, 0.0)).rgb;
    return length(c - n) + length(c - e);
}

// --- LIFECYCLE SYSTEM ---
// Returns a value 0.0 to 1.0 representing how "alive" the box is.
// 0.0 = Hidden, 1.0 = Fully Visible
float getLifecycle(vec2 id) {
    // Unique offset for each box
    float rnd = hash(id);

    // Cycle based on time and speed
    // The sin wave goes from -1 to 1.
    float cycle = sin(uTime * uAppearSpeed + rnd * 6.28);

    // We adjust the wave so it spends more time "off" than "on" for a scanning look
    // smoothstep creates the grow/shrink animation
    float life = smoothstep(-0.4, -0.1, cycle) * (1.0 - smoothstep(0.6, 0.9, cycle));

    // If Speed is 0.0, freeze everything to fully visible (or random state)
    if (uAppearSpeed <= 0.01) return 1.0;

    return life;
}

// Get Node Position (Screen Space)
vec2 getNodePos(vec2 id, vec2 gridDims, vec2 aspect) {
    vec2 cellBaseUV = id / gridDims;
    float t = uTime * 1.0 + hash(id) * 10.0;
    vec2 jitter = vec2(sin(t), cos(t * 0.9)) * 0.002;
    return (cellBaseUV + (0.5 / gridDims) + jitter) * aspect;
}

// Get Dimensions (Tall vs Wide)
vec2 getBoxDimensions(vec2 id) {
    float rnd = hash(id);
    float scale = 1.0 / uGridSize; 
    vec2 dims;
    if (rnd < uVerticalChance) {
        float w = mix(uMinWidth, 0.3, hash(id + 1.0));
        float h = mix(uMinHeight, uMaxHeight, hash(id + 2.0));
        dims = vec2(w, h) * scale;
    } else {
        float w = mix(0.5, 0.9, hash(id + 1.0));
        float h = mix(0.15, 0.25, hash(id + 2.0));
        dims = vec2(w, h) * scale;
    }
    return dims * 0.5;
}

// SDFs
float boxSDF(vec2 p, vec2 b, float thickness, float pixelWidth) {
    vec2 d = abs(p) - b;
    float dist = length(max(d, 0.0)) + min(max(d.x, d.y), 0.0);
    return 1.0 - smoothstep(thickness, thickness + pixelWidth * 1.5, abs(dist));
}

float lineSDF(vec2 p, vec2 a, vec2 b, float thickness, float pixelWidth) {
    vec2 pa = p - a;
    vec2 ba = b - a;
    float h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
    return 1.0 - smoothstep(thickness, thickness + pixelWidth * 2.0, length(pa - ba * h));
}

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
    vec2 aspect = vec2(uResolution.x / uResolution.y, 1.0);
    float pixelWidth = 1.0 / uResolution.y;
    vec2 p = uv * aspect;

    vec2 gridDims = vec2(uGridSize * aspect.x, uGridSize);
    vec2 baseID = floor(uv * gridDims);

    float totalBoxes = 0.0;
    float totalLines = 0.0;
    float totalText = 0.0;
    float totalDots = 0.0;

    // Search wide (5x5) to catch long boxes and bridges
    for (float x = -3.0; x <= 3.0; x++) {
        for (float y = -3.0; y <= 3.0; y++) {
            vec2 neighborID = baseID + vec2(x, y);

            // 1. CHECK EDGE (Is there an object?)
            vec2 cellBaseUV = neighborID / gridDims;
            vec2 trackPosUV = cellBaseUV + (0.5 / gridDims); // Sample center
            float edge = getEdgeIntensity(trackPosUV);

            // 2. CHECK LIFECYCLE (Animation state 0.0 to 1.0)
            float life = getLifecycle(neighborID);

            // Only draw if edge exists AND life is starting
            if (edge > uThreshold && life > 0.01) {

                vec2 nodePos = getNodePos(neighborID, gridDims, aspect);
                vec2 boxDim = getBoxDimensions(neighborID);

                // ANIMATION: Scale box by Life
                // It grows out from center
                boxDim *= life; 

                // --- DRAW BOX ---
                vec2 diff = p - nodePos;
                float box = boxSDF(diff, boxDim, uLineThickness * 0.8, pixelWidth);
                totalBoxes = max(totalBoxes, box);

                // --- DRAW DOT ---
                // Scale dot too so it pops
                float dotSize = 0.003 * life;
                float dot = 1.0 - smoothstep(dotSize, dotSize + pixelWidth*2.0, length(diff));
                totalDots = max(totalDots, dot);

                // --- DRAW TEXT ---
                // Only show text if box is mostly grown (> 0.5 life)
                if (life > 0.5) {
                    vec2 textOrigin = nodePos + vec2(-boxDim.x, boxDim.y + 0.015);
                    vec2 textDiff = p - textOrigin;
                    vec2 textUV = textDiff * 60.0;
                    textUV.y = -textUV.y;

                    if (abs(textDiff.x) < 0.1 && abs(textDiff.y) < 0.1) {
                        totalText += drawNumberSequence(textUV, neighborID);
                    }
                }

                // --- CONNECTIVITY (Bridging) ---
                // Connect to Right (1,0) and Down (0,1)
                // Bridge over gaps if neighbor is missing/dead

                vec2 checkDirs[2];
                checkDirs[0] = vec2(1.0, 0.0);
                checkDirs[1] = vec2(0.0, 1.0);

                for(int i=0; i<2; i++) {
                    vec2 targetID = neighborID + checkDirs[i];
                    bool found = false;
                    float targetLife = 0.0;

                    // Check Immediate Neighbor
                    vec2 tUV = (targetID / gridDims) + (0.5 / gridDims);
                    if (getEdgeIntensity(tUV) > uThreshold) {
                         targetLife = getLifecycle(targetID);
                         if (targetLife > 0.01) found = true;
                    }

                    // If not found, Bridge (Check 2 steps)
                    if (!found) {
                        targetID = neighborID + (checkDirs[i] * 2.0);
                        tUV = (targetID / gridDims) + (0.5 / gridDims);
                         if (getEdgeIntensity(tUV) > uThreshold) {
                             targetLife = getLifecycle(targetID);
                             if (targetLife > 0.01) found = true;
                        }
                    }

                    if (found) {
                        // Line thickness/opacity scales with the WEAKEST link
                        // If one box is shrinking, the line shrinks with it
                        float combinedLife = min(life, targetLife);

                        vec2 targetPos = getNodePos(targetID, gridDims, aspect);

                        // Scale line thickness by life
                        float currentThick = uLineThickness * combinedLife;

                        float ln = lineSDF(p, nodePos, targetPos, currentThick, pixelWidth);
                        totalLines = max(totalLines, ln);
                    }
                }
            }
        }
    }

    vec4 scene = texture2D(uPreviousFrame, uv);
    vec3 sceneDim = scene.rgb * 0.6; 

    vec3 ui = (totalBoxes * uBoxColor) + 
              (totalLines * uLineColor) + 
              (totalDots * uBoxColor) +
              (totalText * uBoxColor * uTextOpacity);

    outputColor = vec4(sceneDim + ui, 1.0);
}

