uniform sampler2D uPreviousFrame;
uniform vec2 uResolution;
uniform vec2 uMouse;

// --- CONTROLS ---
uniform float uRadius;
uniform float uSamples;
uniform float uBlurStrength;
uniform int uShapeType;
uniform float uSharpenStrength; // <-- ADDED THIS

// Gaussian weight for blur
float gaussian(float x, float sigma) {
    return exp(-(x * x) / (2.0 * sigma * sigma));
}

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
    float dist = distance(uv, uMouse);

    // How wide the smooth transition zone is (0.05 = 5% of the screen)
    // You can also make this a uniform (e.g., uFadeWidth) if you want to control it!
    float fadeWidth = 0.05; 

    // Smoothstep creates a beautiful S-curve fade between the two values
    float fadeMask = smoothstep(uRadius - fadeWidth, uRadius + fadeWidth, dist);

    vec4 sharpColor = vec4(0.0);
    vec4 blurredColor = vec4(0.0);

    // ==========================================
    // 1. CALCULATE SHARPEN (Inside the radius)
    // ==========================================
    if (fadeMask < 1.0) {
        vec2 texel = 1.0 / uResolution;

        // Sample the current pixel and its 4 immediate neighbors
        vec4 center = texture2D(uPreviousFrame, uv);
        vec4 top    = texture2D(uPreviousFrame, uv + vec2(0.0, -texel.y));
        vec4 bottom = texture2D(uPreviousFrame, uv + vec2(0.0, texel.y));
        vec4 left   = texture2D(uPreviousFrame, uv + vec2(-texel.x, 0.0));
        vec4 right  = texture2D(uPreviousFrame, uv + vec2(texel.x, 0.0));

        // Extract the edges
        vec4 edges = (center * 4.0) - (top + bottom + left + right);

        // Add the edges back to the center image using your new Uniform!
        // 0.0 = Normal image (No sharpen)
        // 1.0 = Nice, clean sharpen
        // 2.0+ = Heavy/Aggressive sharpen
        sharpColor = clamp(center + (edges * uSharpenStrength), 0.0, 1.0);
    }

    // ==========================================
    // 2. CALCULATE BLUR (Outside the radius)
    // ==========================================
    if (fadeMask > 0.0) {
        float totalWeight = 0.0;
        int samples = int(uSamples);
        float fSamples = max(1.0, float(samples)); // Prevent division by zero

        // Start the blur slightly inside the edge so the fade connects seamlessly
        float sigma = max(0.001, uBlurStrength * (dist - (uRadius - fadeWidth))); 

        for (int i = 0; i < 128; ++i) { // 128 is a safe ceiling for WebGL loops
            if (i >= samples) break; 

            vec2 offset;
            if (uShapeType == 0) { // Circular blur
                float offsetAngle = float(i) / fSamples * 2.0 * 3.14159; 
                offset = vec2(cos(offsetAngle), sin(offsetAngle)) * sigma;
            } else if (uShapeType == 1) { // Horizontal blur
                offset = vec2(float(i) - fSamples / 2.0, 0.0) / fSamples * sigma * 2.0;
            } else { // Vertical blur
                offset = vec2(0.0, float(i) - fSamples / 2.0) / fSamples * sigma * 2.0;
            }

            vec2 sampleUv = uv + offset;
            float weight = gaussian(length(offset), sigma);
            blurredColor += texture2D(uPreviousFrame, sampleUv) * weight;
            totalWeight += weight;
        }
        blurredColor /= totalWeight;
    }

    // ==========================================
    // 3. COMPOSITE TOGETHER
    // ==========================================
    // Seamless crossfade between sharp and blur based on distance
    outputColor = mix(sharpColor, blurredColor, fadeMask);
}
